#include<bits/stdc++.h>
using namespace std;

int main()
{
	long long t;
	scanf("%lld",&t);
	while(t--)
	{
		long long a,b;
		scanf("%lld%lld",&a,&b);
		if(a==b)
		{
			printf("0\n");
			continue;
		}
		long long min1=INT_MAX;
		for(long long i=1;(1LL<<(i-1))<=b;i++)
		{
			long long ans=0;
			long long tempa=a,tempb=b;
			while(tempb>=(1LL<<i))
			{
				tempb/=2;
			}
			while(tempa>tempb)
			{
				if(tempa%2==1)
				{
					tempa++;
					ans++;
				}
				tempa/=2;
				ans++;
			}
			ans+=tempb-tempa;
			long long cnt=0;
			while((tempb<<(cnt+1))<=b)
			{
				cnt++;
			}
			for(long long j=0;j<cnt;j++)
			{
				ans+=((b>>j)&1)+1;
			}
			min1=min(min1,ans);
		}
		printf("%lld\n",min1);
	}
	return 0;
}
